from __future__ import annotations

import json
import re
from pathlib import Path
from typing import Any


REQUIRED_TOP_LEVEL_FIELDS = {
    "batch_id",
    "scenes",
}

REQUIRED_SCENE_FIELDS = {
    "scene_id",
    "narration_original",
    "narration_tts",
}

ERROR_SEVERITY = {
    "payload_unreadable": "fatal_contract_error",
    "output_unreadable": "fatal_contract_error",
    "invalid_top_level_shape": "fatal_contract_error",
    "empty_scenes": "fatal_contract_error",
    "scene_count_mismatch": "batch_regenerate",
    "scene_order_mismatch": "batch_regenerate",
    "missing_required_field": "structural_patch",
    "missing_scene_output": "scene_subset_repair",
    "unexpected_scene_output": "batch_regenerate",
    "narration_original_mismatch": "scene_subset_repair",
    "empty_narration_tts": "scene_subset_repair",
    "meaningful_change_detected": "scene_subset_repair",
}

CLASSIFICATION_PRIORITY = [
    "fatal_contract_error",
    "batch_regenerate",
    "scene_subset_repair",
    "structural_patch",
    "needs_semantic_review",
    "ok",
]

NO_CHANGE_NORMALIZED_EQUIVALENTS = {
    "°c": "degrees celsius",
    "ºc": "degrees celsius",
    "��c": "degrees celsius",
    "dr.": "dr",
    "«": '"',
    "»": '"',
}


def validate_tts_polish_output(
    *,
    batch_payload_path: str | Path,
    batch_output_path: str | Path,
) -> dict[str, Any]:
    errors: list[dict[str, Any]] = []
    warnings: list[dict[str, Any]] = []

    payload_result = _load_json(batch_payload_path, error_code="payload_unreadable")
    if not payload_result["ok"]:
        return _fatal_result(batch_id=None, errors=payload_result["errors"], warnings=warnings)

    output_result = _load_json(batch_output_path, error_code="output_unreadable")
    if not output_result["ok"]:
        payload = payload_result["data"]
        return _fatal_result(
            batch_id=_extract_batch_id_from_payload(payload),
            errors=output_result["errors"],
            warnings=warnings,
        )

    payload = payload_result["data"]
    output = output_result["data"]
    expected_batch_id = _extract_batch_id_from_payload(payload)
    batch_id = _extract_batch_id(output) or expected_batch_id

    source_scenes = payload.get("scenes") if isinstance(payload, dict) else None
    if not isinstance(source_scenes, list) or not source_scenes:
        errors.append(_error("invalid_top_level_shape", "Batch payload must include non-empty 'scenes' list"))
        return _finalize_result(
            batch_id=batch_id,
            errors=errors,
            warnings=warnings,
            changed_scene_count=0,
            flagged_scene_count=0,
            source_scene_count=0,
        )

    output_scenes = _validate_top_level_output(output, errors)
    if not output_scenes:
        return _finalize_result(
            batch_id=batch_id,
            errors=errors,
            warnings=warnings,
            changed_scene_count=0,
            flagged_scene_count=0,
            source_scene_count=len(source_scenes),
        )

    source_ids = [scene.get("scene_id") for scene in source_scenes if isinstance(scene, dict)]
    output_ids = [scene.get("scene_id") for scene in output_scenes if isinstance(scene, dict)]

    if expected_batch_id and _extract_batch_id(output) and _extract_batch_id(output) != expected_batch_id:
        errors.append(_error(
            "missing_required_field",
            f"Output batch_id '{_extract_batch_id(output)}' does not match expected '{expected_batch_id}'",
        ))

    if len(output_scenes) != len(source_scenes):
        errors.append(_error(
            "scene_count_mismatch",
            f"Expected {len(source_scenes)} scenes but found {len(output_scenes)}",
        ))

    _validate_required_scene_fields(output_scenes, errors)
    _validate_scene_mapping(source_ids, output_ids, errors)

    source_map = {
        scene.get("scene_id"): scene
        for scene in source_scenes
        if isinstance(scene, dict) and scene.get("scene_id")
    }

    changed_scene_count = 0
    flagged_scene_ids: set[str] = set()

    for scene in output_scenes:
        scene_id = scene.get("scene_id")
        if not isinstance(scene_id, str) or scene_id not in source_map:
            continue

        source_scene = source_map[scene_id]
        source_original = source_scene.get("narration_original")
        output_original = scene.get("narration_original")
        narration_tts = scene.get("narration_tts")

        if not isinstance(output_original, str) or output_original != source_original:
            errors.append(_error(
                "narration_original_mismatch",
                f"Scene {scene_id} narration_original does not match source payload",
                scene_ids=[scene_id],
            ))
            flagged_scene_ids.add(scene_id)

        if not isinstance(narration_tts, str) or not narration_tts.strip():
            errors.append(_error(
                "empty_narration_tts",
                f"Scene {scene_id} must include non-empty narration_tts",
                scene_ids=[scene_id],
            ))
            flagged_scene_ids.add(scene_id)
            continue

        if isinstance(source_original, str) and _normalize_text(narration_tts) != _normalize_text(source_original):
            changed_scene_count += 1
            if _is_meaningfully_different(source_original, narration_tts):
                errors.append(_error(
                    "meaningful_change_detected",
                    f"Scene {scene_id} narration_tts differs from source in a way that may require semantic review",
                    scene_ids=[scene_id],
                ))
                flagged_scene_ids.add(scene_id)

    return _finalize_result(
        batch_id=batch_id,
        errors=errors,
        warnings=warnings,
        changed_scene_count=changed_scene_count,
        flagged_scene_count=len(flagged_scene_ids),
        source_scene_count=len(source_scenes),
    )


def _load_json(path: str | Path, *, error_code: str) -> dict[str, Any]:
    path = Path(path)
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception as exc:  # noqa: BLE001
        return {
            "ok": False,
            "errors": [_error(error_code, f"Failed to read JSON from {path}: {exc}")],
        }
    return {"ok": True, "data": data}


def _validate_top_level_output(output: Any, errors: list[dict[str, Any]]) -> list[dict[str, Any]]:
    if not isinstance(output, dict):
        errors.append(_error("invalid_top_level_shape", "TTS polish output must be a JSON object"))
        return []

    missing_top_level = sorted(REQUIRED_TOP_LEVEL_FIELDS - set(output.keys()))
    if missing_top_level:
        errors.append(_error(
            "invalid_top_level_shape",
            f"Output is missing top-level fields: {', '.join(missing_top_level)}",
        ))

    scenes = output.get("scenes")
    if not isinstance(scenes, list):
        errors.append(_error("invalid_top_level_shape", "Output 'scenes' must be a list"))
        return []

    if not scenes:
        errors.append(_error("empty_scenes", "Output 'scenes' list is empty"))
        return []

    valid_scenes: list[dict[str, Any]] = []
    for index, scene in enumerate(scenes, start=1):
        if not isinstance(scene, dict):
            errors.append(_error(
                "missing_required_field",
                f"Scene at index {index} must be an object",
                scene_ids=[f"scene_index_{index}"],
            ))
            continue
        valid_scenes.append(scene)

    return valid_scenes


def _validate_required_scene_fields(scenes: list[dict[str, Any]], errors: list[dict[str, Any]]) -> None:
    for scene in scenes:
        missing_fields = sorted(REQUIRED_SCENE_FIELDS - set(scene.keys()))
        if missing_fields:
            errors.append(_error(
                "missing_required_field",
                (
                    f"Scene {scene.get('scene_id', '<unknown>')} is missing required fields: "
                    f"{', '.join(missing_fields)}"
                ),
                scene_ids=[scene.get("scene_id")],
            ))


def _validate_scene_mapping(source_ids: list[Any], output_ids: list[Any], errors: list[dict[str, Any]]) -> None:
    if source_ids != output_ids:
        errors.append(_error(
            "scene_order_mismatch",
            "Output scene order/identity does not match input batch scene_ids",
            scene_ids=[str(scene_id) for scene_id in output_ids if scene_id],
        ))

    source_set = {scene_id for scene_id in source_ids if isinstance(scene_id, str)}
    output_set = {scene_id for scene_id in output_ids if isinstance(scene_id, str)}

    missing_ids = sorted(source_set - output_set)
    unexpected_ids = sorted(output_set - source_set)

    for scene_id in missing_ids:
        errors.append(_error(
            "missing_scene_output",
            f"Expected scene {scene_id} is missing from polish output",
            scene_ids=[scene_id],
        ))

    for scene_id in unexpected_ids:
        errors.append(_error(
            "unexpected_scene_output",
            f"Unexpected scene {scene_id} found in polish output",
            scene_ids=[scene_id],
        ))


def _extract_batch_id(output: dict[str, Any]) -> str | None:
    batch_id = output.get("batch_id") or output.get("batch", {}).get("batch_id")
    return batch_id if isinstance(batch_id, str) and batch_id.strip() else None


def _extract_batch_id_from_payload(payload: dict[str, Any]) -> str | None:
    batch = payload.get("batch") if isinstance(payload, dict) else None
    if not isinstance(batch, dict):
        return None
    batch_id = batch.get("batch_id")
    return batch_id if isinstance(batch_id, str) and batch_id.strip() else None


def _normalize_text(text: str) -> str:
    text = text.replace("\r\n", " ").replace("\n", " ").replace("\t", " ")
    text = re.sub(r"\s+", " ", text).strip().lower()
    return text


def _canonicalize_equivalents(text: str) -> str:
    normalized = _normalize_text(text)
    for old, new in NO_CHANGE_NORMALIZED_EQUIVALENTS.items():
        normalized = normalized.replace(old, new)
    normalized = re.sub(r"\bdr\b", "dr.", normalized)
    normalized = re.sub(r"\b(\d+)\s+kilometers\b", r"\1 km", normalized)
    normalized = re.sub(r"\b(\d+)\s+kilograms\b", r"\1 kg", normalized)
    normalized = re.sub(r"\b(\d+)\s+meters\b", r"\1 m", normalized)
    normalized = re.sub(r"(\d+)degrees celsius\b", r"\1 °c", normalized)
    normalized = re.sub(r"\b(\d+)\s+degrees celsius\b", r"\1 °c", normalized)
    normalized = normalized.replace("��c", "°c")
    return normalized


def _is_meaningfully_different(source: str, polished: str) -> bool:
    source_canonical = _canonicalize_equivalents(source)
    polished_canonical = _canonicalize_equivalents(polished)
    if source_canonical == polished_canonical:
        return False

    source_light = re.sub(r'[()“”"«»]', ' ', source_canonical)
    polished_light = re.sub(r'[()“”"«»]', ' ', polished_canonical)
    source_light = re.sub(r'\s+', ' ', source_light).strip()
    polished_light = re.sub(r'\s+', ' ', polished_light).strip()
    return source_light != polished_light


def _error(code: str, message: str, *, scene_ids: list[str | None] | None = None) -> dict[str, Any]:
    clean_scene_ids = [scene_id for scene_id in (scene_ids or []) if scene_id]
    payload: dict[str, Any] = {"code": code, "message": message}
    if clean_scene_ids:
        payload["scene_ids"] = clean_scene_ids
    return payload


def _fatal_result(*, batch_id: str | None, errors: list[dict[str, Any]], warnings: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "ok": False,
        "approved_for_merge": False,
        "batch_id": batch_id,
        "classification": "fatal_contract_error",
        "errors": errors,
        "warnings": warnings,
        "stats": {
            "scene_count": 0,
            "changed_scene_count": 0,
            "flagged_scene_count": 0,
        },
    }


def _finalize_result(
    *,
    batch_id: str | None,
    errors: list[dict[str, Any]],
    warnings: list[dict[str, Any]],
    changed_scene_count: int,
    flagged_scene_count: int,
    source_scene_count: int,
) -> dict[str, Any]:
    classification = _classify_errors(errors)
    return {
        "ok": classification == "ok",
        "approved_for_merge": classification == "ok",
        "batch_id": batch_id,
        "classification": classification,
        "errors": errors,
        "warnings": warnings,
        "stats": {
            "scene_count": source_scene_count,
            "changed_scene_count": changed_scene_count,
            "flagged_scene_count": flagged_scene_count,
        },
    }


def _classify_errors(errors: list[dict[str, Any]]) -> str:
    if not errors:
        return "ok"

    severities = [ERROR_SEVERITY.get(error.get("code"), "fatal_contract_error") for error in errors]
    for classification in CLASSIFICATION_PRIORITY:
        if classification in severities:
            return classification
    return "fatal_contract_error"

from __future__ import annotations

import json
from pathlib import Path
from typing import Any


REQUIRED_POLISH_FIELDS = {
    "scene_id",
    "narration_original",
    "narration_tts",
}


def merge_tts_polish_batches(
    batch_files: list[str | Path],
    *,
    screenplay: dict[str, Any],
    output_path: str | Path | None = None,
) -> dict[str, Any]:
    errors: list[dict[str, str]] = []
    warnings: list[dict[str, str]] = []
    ordered_files = sorted([Path(p) for p in batch_files], key=lambda p: p.name)

    scenes = screenplay.get("scenes", []) if isinstance(screenplay, dict) else []
    ordered_scene_ids = [scene.get("scene_id") for scene in scenes if isinstance(scene, dict) and scene.get("scene_id")]

    if not ordered_files:
        return {
            "ok": False,
            "scene_count": 0,
            "tts_polished": {"scenes": []},
            "errors": [{"code": "no_batch_files", "message": "No tts_polish batch files provided"}],
            "warnings": [],
        }

    polish_map: dict[str, dict[str, Any]] = {}
    loaded_batches: list[dict[str, Any]] = []

    for file_path in ordered_files:
        if not file_path.exists():
            errors.append({
                "code": "missing_batch_file",
                "message": f"Polish batch file not found: {file_path}",
            })
            continue

        try:
            payload = json.loads(file_path.read_text(encoding="utf-8"))
        except Exception as exc:  # noqa: BLE001
            errors.append({
                "code": "invalid_batch_json",
                "message": f"Failed to parse polish batch file {file_path}: {exc}",
            })
            continue

        batch_id = payload.get("batch_id")
        batch_scenes = payload.get("scenes", [])
        if not isinstance(batch_scenes, list):
            errors.append({
                "code": "invalid_batch_scenes",
                "message": f"Polish batch file {file_path} has invalid 'scenes' payload",
            })
            continue

        if not batch_scenes:
            warnings.append({
                "code": "empty_polish_batch",
                "message": f"Polish batch file {file_path} produced zero scenes",
            })

        loaded_batches.append(
            {
                "batch_id": batch_id,
                "file_path": str(file_path),
                "scene_count": len(batch_scenes),
            }
        )

        for scene in batch_scenes:
            if not isinstance(scene, dict):
                errors.append({
                    "code": "invalid_scene_payload",
                    "message": f"Polish batch {batch_id or file_path.name} contains a non-object scene entry",
                })
                continue

            missing_fields = sorted(REQUIRED_POLISH_FIELDS - set(scene.keys()))
            if missing_fields:
                errors.append({
                    "code": "missing_polish_fields",
                    "message": (
                        f"Polish batch {batch_id or file_path.name} scene is missing required fields: "
                        f"{', '.join(missing_fields)}"
                    ),
                })
                continue

            scene_id = scene.get("scene_id")
            if scene_id in polish_map:
                warnings.append({
                    "code": "duplicate_scene_polish",
                    "message": f"Scene {scene_id} appeared more than once across polish batches; latest entry kept",
                })
            polish_map[scene_id] = scene

    merged_scenes: list[dict[str, Any]] = []
    for scene_id in ordered_scene_ids:
        polished_scene = polish_map.get(scene_id)
        if not polished_scene:
            errors.append({
                "code": "missing_polish_scene",
                "message": f"No polish output found for screenplay scene {scene_id}",
            })
            continue
        merged_scenes.append(polished_scene)

    tts_polished = {
        "scene_count": len(merged_scenes),
        "scenes": merged_scenes,
    }

    if output_path is not None:
        output_path = Path(output_path)
        output_path.parent.mkdir(parents=True, exist_ok=True)
        output_path.write_text(json.dumps(tts_polished, indent=2, ensure_ascii=False), encoding="utf-8")

    return {
        "ok": len(errors) == 0,
        "scene_count": len(merged_scenes),
        "batch_count": len(loaded_batches),
        "tts_polished": tts_polished,
        "loaded_batches": loaded_batches,
        "output_path": str(output_path) if output_path is not None else None,
        "errors": errors,
        "warnings": warnings,
    }

